function useReveal() {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: "-60px" });
  return [ref, inView];
}

function CustomCursor() {
  const [pos, setPos] = useState({ x: -100, y: -100 });
  const [hovered, setHovered] = useState(false);
  const [label, setLabel] = useState("");
  useEffect(() => {
    const move = (e) => setPos({ x: e.clientX, y: e.clientY });
    const over = (e) => {
      const el = e.target.closest("[data-cursor]");
      if (el) { setHovered(true); setLabel(el.dataset.cursor); }
      else { setHovered(false); setLabel(""); }
    };
    window.addEventListener("mousemove", move);
    window.addEventListener("mouseover", over);
    return () => { window.removeEventListener("mousemove", move); window.removeEventListener("mouseover", over); };
  }, []);
  return (
    <>
      <motion.div
        animate={{ x: pos.x-6, y: pos.y-6, scale: hovered?0:1 }}
        transition={{ type:"spring", stiffness:800, damping:40, mass:0.2 }}
        style={{ position:"fixed", top:0, left:0, width:12, height:12, borderRadius:"50%", background:"#F5C518", pointerEvents:"none", zIndex:9999 }}
      />
      <motion.div
        animate={{ x: pos.x-(hovered?44:22), y: pos.y-(hovered?44:22) }}
        transition={{ type:"spring", stiffness:200, damping:28 }}
        style={{ position:"fixed", top:0, left:0, width:hovered?88:44, height:hovered?88:44, borderRadius:"50%", border:"1px solid rgba(245,197,24,0.5)", display:"flex", alignItems:"center", justifyContent:"center", pointerEvents:"none", zIndex:9998, transition:"width 0.3s, height 0.3s" }}
      >
        {label && <span style={{ fontSize:8, letterSpacing:"0.2em", color:"#F5C518", fontFamily:"monospace", textTransform:"uppercase" }}>{label}</span>}
      </motion.div>
    </>
  );
}

