function Lightbox({ item, onClose, onPrev, onNext }) {
  useEffect(() => {
    const fn = (e) => {
      if (e.key==="Escape") onClose();
      if (e.key==="ArrowRight") onNext();
      if (e.key==="ArrowLeft") onPrev();
    };
    window.addEventListener("keydown", fn);
    document.body.style.overflow = "hidden";
    return () => { window.removeEventListener("keydown", fn); document.body.style.overflow = ""; };
  }, [onClose, onNext, onPrev]);
  return (
    <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }}
      onClick={onClose}
      style={{ position:"fixed", inset:0, zIndex:9000, background:"rgba(0,0,0,0.96)", display:"flex", alignItems:"center", justifyContent:"center", padding:24, backdropFilter:"blur(16px)" }}>
      <motion.div initial={{ scale:0.85, opacity:0 }} animate={{ scale:1, opacity:1 }} exit={{ scale:0.85, opacity:0 }}
        transition={{ duration:0.4, ease:[0.22,1,0.36,1] }}
        onClick={e=>e.stopPropagation()}
        style={{ position:"relative", maxWidth:"88vw", maxHeight:"92vh", display:"flex", flexDirection:"column", alignItems:"center" }}>
        <img src={item.img} alt={item.title}
          style={{ maxWidth:"100%", maxHeight:"80vh", objectFit:"contain", border:"1px solid rgba(245,197,24,0.15)" }} />
        <div style={{ marginTop:16, display:"flex", alignItems:"center", gap:16 }}>
          <span style={{ fontFamily:"monospace", fontSize:9, letterSpacing:"0.25em", color:"rgba(245,197,24,0.6)", textTransform:"uppercase" }}>{item.cat}</span>
          <div style={{ width:1, height:12, background:"rgba(255,255,255,0.2)" }} />
          <span style={{ fontFamily:"'Bebas Neue', sans-serif", fontSize:20, color:"#fff", letterSpacing:"0.1em" }}>{item.title}</span>
        </div>
        <motion.button onClick={onClose} whileHover={{ scale:1.1 }}
          style={{ position:"absolute", top:-16, right:-16, width:40, height:40, borderRadius:"50%", background:"#F5C518", border:"none", cursor:"pointer", fontSize:20, color:"#000", fontWeight:"bold" }}>
          x
        </motion.button>
        <motion.button onClick={e=>{e.stopPropagation();onPrev();}} whileHover={{ scale:1.1 }}
          style={{ position:"absolute", left:-56, top:"50%", transform:"translateY(-50%)", width:44, height:44, borderRadius:"50%", background:"rgba(245,197,24,0.15)", border:"1px solid rgba(245,197,24,0.3)", cursor:"pointer", color:"#F5C518", fontSize:24 }}>
          &lt;
        </motion.button>
        <motion.button onClick={e=>{e.stopPropagation();onNext();}} whileHover={{ scale:1.1 }}
          style={{ position:"absolute", right:-56, top:"50%", transform:"translateY(-50%)", width:44, height:44, borderRadius:"50%", background:"rgba(245,197,24,0.15)", border:"1px solid rgba(245,197,24,0.3)", cursor:"pointer", color:"#F5C518", fontSize:24 }}>
          &gt;
        </motion.button>
      </motion.div>
    </motion.div>
  );
}

